using Microsoft.ML.Data;

namespace TicketClassifier.Models;

/// <summary>
/// Input schema for the ML.NET training pipeline.
/// </summary>
public sealed class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

/// <summary>
/// Output schema produced by the trained model.
/// </summary>
public sealed class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedCategory { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public sealed class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public sealed class TicketPredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Scores { get; set; } = new();
}

public sealed class TrainingMetricsResponse
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public PerClassMetric[] PerClassMetrics { get; set; } = [];
}

public sealed class PerClassMetric
{
    public string ClassName { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

/// <summary>
/// Trains the ticket classification model at startup and exposes evaluation metrics.
/// </summary>
public sealed class TicketModelService
{
    private readonly string _modelPath;
    private readonly string _dataPath;
    private readonly ILogger<TicketModelService> _logger;

    public TrainingMetricsResponse? Metrics { get; private set; }

    // Category labels discovered during training, used for score mapping.
    public string[] CategoryLabels { get; private set; } = [];

    public TicketModelService(ILogger<TicketModelService> logger)
    {
        _logger = logger;
        _dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        _modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
    }

    public void TrainAndEvaluate()
    {
        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // With only 6 rows we use the full dataset for both training and evaluation
        // to produce meaningful metrics. In production, use TrainTestSplit.
        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.3, seed: 42);

        // Combine Subject + Description into a single text feature, then featurize.
        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training ticket classification model...");
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on test split.
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        _logger.LogInformation(
            "Model trained — MacroAccuracy: {MacroAccuracy:F4}, MicroAccuracy: {MicroAccuracy:F4}, LogLoss: {LogLoss:F4}",
            metrics.MacroAccuracy, metrics.MicroAccuracy, metrics.LogLoss);

        // Build per-class metrics from the confusion matrix.
        var perClass = metrics.ConfusionMatrix.PerClassPrecision
            .Zip(metrics.ConfusionMatrix.PerClassRecall, (p, r) => (Precision: p, Recall: r))
            .Select((m, i) => new PerClassMetric
            {
                ClassName = metrics.ConfusionMatrix.PredictedClassesIndicators[i],
                Precision = m.Precision,
                Recall = m.Recall,
            })
            .ToArray();

        Metrics = new TrainingMetricsResponse
        {
            MacroAccuracy = metrics.MacroAccuracy,
            MicroAccuracy = metrics.MicroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction,
            PerClassMetrics = perClass,
        };

        // Extract category labels for score mapping.
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        predictions.Schema["Score"].GetSlotNames(ref labelBuffer);
        CategoryLabels = labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();

        // Save the trained model.
        mlContext.Model.Save(model, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public sealed class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _pool;
    private readonly TicketModelService _modelService;

    public TicketsController(
        PredictionEnginePool<TicketData, TicketPrediction> pool,
        TicketModelService modelService)
    {
        _pool = pool;
        _modelService = modelService;
    }

    /// <summary>
    /// Predict the category for a support ticket.
    /// </summary>
    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = _pool.Predict(input);

        var scores = _modelService.CategoryLabels
            .Zip(prediction.Score, (label, score) => (label, score))
            .ToDictionary(x => x.label, x => x.score);

        return Ok(new TicketPredictionResponse
        {
            PredictedCategory = prediction.PredictedCategory,
            Scores = scores,
        });
    }

    /// <summary>
    /// Return evaluation metrics from the last training run.
    /// </summary>
    [HttpGet("metrics")]
    public ActionResult<TrainingMetricsResponse> GetMetrics()
    {
        if (_modelService.Metrics is null)
            return StatusCode(503, "Model has not been trained yet.");

        return Ok(_modelService.Metrics);
    }
}

