using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public sealed class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _pool;
    private readonly TicketModelService _modelService;

    public TicketsController(
        PredictionEnginePool<TicketData, TicketPrediction> pool,
        TicketModelService modelService)
    {
        _pool = pool;
        _modelService = modelService;
    }

    /// <summary>
    /// Predict the category for a support ticket.
    /// </summary>
    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = _pool.Predict(input);

        var scores = _modelService.CategoryLabels
            .Zip(prediction.Score, (label, score) => (label, score))
            .ToDictionary(x => x.label, x => x.score);

        return Ok(new TicketPredictionResponse
        {
            PredictedCategory = prediction.PredictedCategory,
            Scores = scores,
        });
    }

    /// <summary>
    /// Return evaluation metrics from the last training run.
    /// </summary>
    [HttpGet("metrics")]
    public ActionResult<TrainingMetricsResponse> GetMetrics()
    {
        if (_modelService.Metrics is null)
            return StatusCode(503, "Model has not been trained yet.");

        return Ok(_modelService.Metrics);
    }
}

