using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Register model service as a singleton.
builder.Services.AddSingleton<TicketModelService>();

// Thread-safe prediction engine pool (never use PredictionEngine as a singleton).
var modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
builder.Services.AddPredictionEnginePool<TicketData, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

// Train the model before the app starts serving requests.
var modelService = app.Services.GetRequiredService<TicketModelService>();
modelService.TrainAndEvaluate();

app.MapControllers();
app.Run();

